#!/usr/bin/env node
// Calibrate Elo ratings on real recent internationals (data/results.json) → data/elo-calibrated.json.
// Seeds loaded from data/seeds.json (generated by build-seeds.mjs from 2016-2025 data), then nudged
// with actual form (importance- & recency-weighted). A second pass (no SEED blend, 90-day half-life)
// produces data/elo-form.json for the Elo+form ensemble used by predict.mjs / track-record.mjs.
//   node build-seeds.mjs   (once, or when you want to refresh the 10-year prior)
//   node calibrate.mjs
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { HOME_ADV } from "./elo.mjs";

const D = (f) => new URL(`./data/${f}`, import.meta.url);

// Load data-driven seeds (2016-2025). Fall back to flat 1500 if file missing — run build-seeds.mjs first.
const seedsFile = D("seeds.json");
const SEED = existsSync(seedsFile)
  ? JSON.parse(readFileSync(seedsFile, "utf8")).seeds
  : (() => { console.warn("[calibrate] data/seeds.json not found — run node build-seeds.mjs first. Using flat 1500 prior."); return {}; })();
const HOST = new Set(["mexico", "usa", "canada"]);

// Match-importance K-factor by competition.
function baseK(leagueName = "") {
  const n = leagueName.toLowerCase();
  if (/world cup(?!.*qual)/.test(n)) return 55;
  if (/world cup.*qual|qualification/.test(n)) return 40;
  if (/copa america|euro championship\b|asian cup|africa cup|gold cup/.test(n)) return 50;
  if (/nations league|nations cup/.test(n)) return 32;
  if (/friendl/.test(n)) return 18;
  return 28;
}
const recency = (tsSec, nowSec) => Math.pow(0.5, ((nowSec - tsSec) / (30.44 * 86400)) / 18); // 18-mo half-life
const expectedScore = (a, b, hb) => 1 / (1 + Math.pow(10, (b - (a + hb)) / 400));
const gMult = (gd) => { const d = Math.abs(gd); return d <= 1 ? 1 : d === 2 ? 1.5 : (11 + d) / 8; };

const { matches } = JSON.parse(readFileSync(D("results.json"), "utf8"));
const nowSec = matches.length ? matches[matches.length - 1].ts : Math.floor(Date.now() / 1000);

const R = {};
const getR = (slug, name) => { const k = slug ?? `ghost:${name}`; if (R[k] == null) R[k] = slug && SEED[slug] != null ? SEED[slug] : 1500; return R[k]; };
const setR = (slug, name, v) => { R[slug ?? `ghost:${name}`] = v; };

let applied = 0;
for (const m of matches) {
  if (m.hg == null || m.ag == null) continue;
  const ra = getR(m.homeSlug, m.homeName), rb = getR(m.awaySlug, m.awayName);
  const homeBonus = HOST.has(m.homeSlug) ? HOME_ADV / 2 : 0;
  const exp = expectedScore(ra, rb, homeBonus);
  const score = m.hg > m.ag ? 1 : m.hg < m.ag ? 0 : 0.5;
  const k = baseK(m.leagueName) * recency(m.ts, nowSec) * gMult(m.hg - m.ag);
  const delta = k * (score - exp);
  setR(m.homeSlug, m.homeName, ra + delta);
  setR(m.awaySlug, m.awayName, rb - delta);
  applied++;
}

// 70% calibrated + 30% prior (damps friendly noise).
const ratings = {};
for (const slug of Object.keys(SEED)) ratings[slug] = Math.round(0.7 * (R[slug] ?? SEED[slug]) + 0.3 * SEED[slug]);

writeFileSync(D("elo-calibrated.json"), JSON.stringify({ matchesApplied: applied, ratings }, null, 2) + "\n");
console.log(`Calibrated ${Object.keys(ratings).length} teams from ${applied} weighted matches → data/elo-calibrated.json`);

// ─── Form ratings (90-day half-life, pure walk-forward, no SEED blend) ────────
// Captures recent form: matches >6 months old contribute <6% weight; last 2 months dominate.
const FORM_HALFLIFE_DAYS = 90;
const recencyForm = (tsSec) => Math.pow(0.5, ((nowSec - tsSec) / (30.44 * 86400)) / FORM_HALFLIFE_DAYS);

const RF = {};
const getRF = (slug, name) => { const k = slug ?? `ghost:${name}`; if (RF[k] == null) RF[k] = slug && SEED[slug] != null ? SEED[slug] : 1500; return RF[k]; };
const setRF = (slug, name, v) => { RF[slug ?? `ghost:${name}`] = v; };

for (const m of matches) {
  if (m.hg == null || m.ag == null) continue;
  const ra = getRF(m.homeSlug, m.homeName), rb = getRF(m.awaySlug, m.awayName);
  const homeBonus = HOST.has(m.homeSlug) ? HOME_ADV / 2 : 0;
  const exp = expectedScore(ra, rb, homeBonus);
  const score = m.hg > m.ag ? 1 : m.hg < m.ag ? 0 : 0.5;
  const k = baseK(m.leagueName) * recencyForm(m.ts) * gMult(m.hg - m.ag);
  const delta = k * (score - exp);
  setRF(m.homeSlug, m.homeName, ra + delta);
  setRF(m.awaySlug, m.awayName, rb - delta);
}

// No SEED blend — pure walk-forward form signal.
const formRatings = {};
for (const slug of Object.keys(SEED)) formRatings[slug] = Math.round(RF[slug] ?? SEED[slug]);
writeFileSync(D("elo-form.json"), JSON.stringify({ halfLifeDays: FORM_HALFLIFE_DAYS, ratings: formRatings }, null, 2) + "\n");
console.log(`Form ratings (${FORM_HALFLIFE_DAYS}d half-life) → data/elo-form.json`);
